document.addEventListener("DOMContentLoaded",function(){var e=document.getElementById("milestoneModal");e&&(e.addEventListener("show.bs.modal",function(i){var t=i.relatedTarget,n=t.getAttribute("data-milestone-id"),d=n?document.getElementById(n)?.closest(".col"):t.closest(".col");if(d){var o=d.cloneNode(!0),m=t.textContent.trim();document.getElementById("milestoneModalLabel").textContent=m||"Milestone Details";var l=document.getElementById("milestoneModalBody");l.innerHTML="",l.appendChild(o);var a=o.querySelector(".card-header");a&&a.remove()}}),e.addEventListener("hidden.bs.modal",function(){document.getElementById("milestoneModalLabel").textContent="",document.getElementById("milestoneModalBody").innerHTML=""}))});
